#include<bits/stdc++.h>
using namespace std;
int n,m;
int a[300010],s[300010],lst[300010];
int lowbit(int x)
{
	return x&-x;
}
void add(int x,int v)
{
	for(int i=x;i<=n;i+=lowbit(i))
	{
		s[i]+=v;
	}
}
int query(int x)
{
	int ans=0;
	for(int i=x;i>=1;i-=lowbit(i))
	{
		ans+=s[i];
	}
	return ans;
}
int main()
{
	scanf("%d%d",&n,&m);
	for(int i=1;i<=n;i++)
	{
		scanf("%d",&a[i]);
	}
	long long ans=0,k=0;
	for(int i=1;i<=n;i++)
	{
		ans+=query(i)-query(lst[a[i]]);
		if(lst[a[i]])
		{
			add(lst[a[i]],-1);
		}
		else
		{
			k++;
		}
		add(i,1);
		lst[a[i]]=i;
	}
	printf("%lld",ans+(k-1)*k/2+k*(m-k));
	return 0;
}
